CREATE TRIGGER [dbo].[OrderItemUnitDataCollection_History]ON [dbo].[OrderItemUnitDataCollection]AFTER INSERT, UPDATE, DELETE ASDECLARE @HistoryAction CHAR(1)set @HistoryAction = (SELECT TOP 1 	CASE 		WHEN i.OrderItemUnitDataCollectionId IS NOT NULL AND d.OrderItemUnitDataCollectionId IS NULL THEN 'I' 		WHEN i.OrderItemUnitDataCollectionId IS NOT NULL AND d.OrderItemUnitDataCollectionId IS NOT NULL THEN 'U' 		WHEN i.OrderItemUnitDataCollectionId IS NULL AND d.OrderItemUnitDataCollectionId IS NOT NULL THEN 'D'		ELSE 'NA'	END AS HistoryActionfrom inserted as i	full outer join deleted as d on i.OrderItemUnitDataCollectionId = d.OrderItemUnitDataCollectionId)IF @HistoryAction = 'I' OR @HistoryAction = 'U'BEGIN	INSERT INTO History.dbo_OrderItemUnitDataCollection([OrderItemUnitDataCollectionId], [OrderItemUnitId], [EquipmentId], [UserId], [BillOfProcessProcessWorkElementAttributeId], [CollectedValue], [CollectedDate], [CollectedDateUtc], [LastModifiedBy], [LastModifiedTime], [LastModifiedTimeUtc],[HistoryAction])	SELECT [OrderItemUnitDataCollectionId], [OrderItemUnitId], [EquipmentId], [UserId], [BillOfProcessProcessWorkElementAttributeId], [CollectedValue], [CollectedDate], [CollectedDateUtc], [LastModifiedBy], [LastModifiedTime], [LastModifiedTimeUtc],@HistoryAction 	FROM insertedENDELSE IF @HistoryAction = 'D'BEGIN	INSERT INTO History.dbo_OrderItemUnitDataCollection([OrderItemUnitDataCollectionId], [OrderItemUnitId], [EquipmentId], [UserId], [BillOfProcessProcessWorkElementAttributeId], [CollectedValue], [CollectedDate], [CollectedDateUtc], [LastModifiedBy], [LastModifiedTime], [LastModifiedTimeUtc],[HistoryAction])	SELECT [OrderItemUnitDataCollectionId], [OrderItemUnitId], [EquipmentId], [UserId], [BillOfProcessProcessWorkElementAttributeId], [CollectedValue], [CollectedDate], [CollectedDateUtc], [LastModifiedBy], [LastModifiedTime], [LastModifiedTimeUtc],@HistoryAction  	FROM deletedEND